import{_ as a,M as t,p as i,q as l,R as e,t as o,N as r,a1 as m}from"./framework-e0dd9823.js";const s={},c=e("h1",{id:"每周一词-common",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#每周一词-common","aria-hidden":"true"},"#"),o(" 每周一词-Common")],-1),h=e("p",null,"2023 年 5 月 10 日 15:29:30",-1),d={href:"https://www.bbc.co.uk/learningenglish/chinese/features/english-in-a-minute/ep-230505",target:"_blank",rel:"noopener noreferrer"},u=m('<h2 id="简介" tabindex="-1"><a class="header-anchor" href="#简介" aria-hidden="true">#</a> 简介</h2><p>形容词“common”是一个非常“common”的英语单词，意思是“常见的，普遍的”。名词短语“in common”的意思是“有相同的（兴趣或经历）”。</p><h2 id="用法总结" tabindex="-1"><a class="header-anchor" href="#用法总结" aria-hidden="true">#</a> 用法总结</h2><ol><li>“Common”作形容词，可以表示“共同的，共有的，常见的”。</li></ol><ul><li>John is a common name in the UK.</li><li>My friends and I have a lot of common interests</li></ul><ol start="2"><li>形容词“common”还可以表示“经常的，普遍的”。</li></ol><ul><li>It&#39;s common to make a toast dinner on a Sunday here.</li><li>Hot weather in the summer is common in many European countries.</li></ul><ol start="3"><li>在英式英语中，名词“common”永安里指“公地，共享草地”。</li></ol><ul><li>I used to play cricket on the village common.</li><li>We spent the afternoon walking the dog on the common.</li></ul><ol start="4"><li>名词短语“（have something） in common”表示“有相同的（兴趣或经历）”。</li></ol><ul><li>I love English, and, if you do too, we have that in common!</li><li>We have a lot in common. That&#39;s why we are best friends.</li></ul>',11);function _(f,p){const n=t("ExternalLinkIcon");return i(),l("div",null,[c,h,e("p",null,[e("a",d,[o("BBC"),r(n)])]),u])}const g=a(s,[["render",_],["__file","word-common.html.vue"]]);export{g as default};
